"use client"

import {
  IdentitySelectorUI,
  type IdentitySelectorUIProps,
} from "./identity-selector-ui"
import {
  useIdentitySelector,
  type UseIdentitySelectorOptions,
  type UseIdentitySelectorReturn,
  type IdentityEntry,
} from "./use-identity-selector"

// ---------------------------------------------------------------------------
// Re-exports
// ---------------------------------------------------------------------------

export {
  IdentitySelectorUI,
  type IdentitySelectorUIProps,
} from "./identity-selector-ui"
export {
  useIdentitySelector,
  type UseIdentitySelectorOptions,
  type UseIdentitySelectorReturn,
  type IdentityEntry,
} from "./use-identity-selector"

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

export interface IdentitySelectorProps {
  /** Pre-loaded list of identities (skips API fetch if provided) */
  identities?: IdentityEntry[]
  /** BAP ID of the currently active identity */
  activeBapId?: string
  /** List of BAP IDs to fetch from the API (used when identities prop is not provided) */
  bapIds?: string[]
  /** Called when the user selects a different identity */
  onSelect?: (bapId: string) => void
  /** Called when the user clicks "Add identity" */
  onAddIdentity?: () => void
  /** Whether to show the "Add identity" button (default: true) */
  showAddIdentity?: boolean
  /** Base URL for the 1sat-stack API (default: https://api.1sat.app) */
  apiUrl?: string
  /** Optional CSS class name */
  className?: string
}

// ---------------------------------------------------------------------------
// Composed component
// ---------------------------------------------------------------------------

/**
 * A dropdown panel for switching between BAP identities.
 *
 * Shows each identity with avatar, display name, and full BAP ID.
 * The active identity is highlighted with a check icon.
 *
 * Provide either a pre-loaded `identities` array or a `bapIds` list
 * to fetch identity data from the 1sat-stack API.
 *
 * @example
 * ```tsx
 * import { IdentitySelector } from "@/components/blocks/identity-selector"
 *
 * // With pre-loaded identities
 * <IdentitySelector
 *   identities={myIdentities}
 *   activeBapId="Go8vCHAa4S6AhXKdRp3nT9wJm"
 *   onSelect={(bapId) => console.log("Selected:", bapId)}
 *   onAddIdentity={() => console.log("Add identity")}
 * />
 *
 * // With API fetch
 * <IdentitySelector
 *   bapIds={["Go8vCHAa4S6AhXKdRp3nT9wJm", "Hk9wBCDe5F7AiYLmNp2qR8xTs"]}
 *   onSelect={(bapId) => console.log("Selected:", bapId)}
 * />
 * ```
 */
export function IdentitySelector({
  identities: identitiesProp,
  activeBapId: activeBapIdProp,
  bapIds,
  onSelect,
  onAddIdentity,
  showAddIdentity = true,
  apiUrl,
  className,
}: IdentitySelectorProps) {
  const hook = useIdentitySelector({
    identities: identitiesProp,
    activeBapId: activeBapIdProp,
    bapIds,
    onSelect,
    onAddIdentity,
    apiUrl,
  })

  return (
    <IdentitySelectorUI
      className={className}
      identities={hook.identities}
      activeBapId={hook.activeBapId}
      isLoading={hook.isLoading}
      error={hook.error}
      onSelect={hook.selectIdentity}
      onAddIdentity={hook.addIdentity}
      showAddIdentity={showAddIdentity}
    />
  )
}

"use client"

import { cn } from "@/lib/utils"
import { Card, CardContent } from "@/components/ui/card"
import { Badge } from "@/components/ui/badge"
import { Separator } from "@/components/ui/separator"
import { Button } from "@/components/ui/button"
import { Skeleton } from "@/components/ui/skeleton"
import { BitcoinAvatar } from "@/registry/new-york/blocks/bitcoin-avatar"
import { Check, Plus, AlertCircle } from "lucide-react"
import type { IdentityEntry } from "./use-identity-selector"

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

export interface IdentitySelectorUIProps {
  /** Optional CSS class name */
  className?: string
  /** List of available identities */
  identities: IdentityEntry[]
  /** Currently active BAP ID */
  activeBapId: string | null
  /** Whether identities are loading */
  isLoading: boolean
  /** Error if fetch failed */
  error: Error | null
  /** Called when an identity row is clicked */
  onSelect: (bapId: string) => void
  /** Called when "Add identity" is clicked */
  onAddIdentity: () => void
  /** Whether to show the "Add identity" button (default: true) */
  showAddIdentity?: boolean
}

// ---------------------------------------------------------------------------
// Loading skeleton
// ---------------------------------------------------------------------------

function IdentitySelectorSkeleton({ className }: { className?: string }) {
  return (
    <Card className={cn("w-full max-w-sm", className)}>
      <CardContent className="flex flex-col gap-1 p-2">
        {[0, 1, 2].map((i) => (
          <div
            key={i}
            className="flex items-center gap-3 rounded-md px-3 py-2.5"
          >
            <Skeleton className="size-10 shrink-0 rounded-full" />
            <div className="flex-1 flex flex-col gap-1.5">
              <Skeleton className="h-4 w-24" />
              <Skeleton className="h-3 w-40" />
            </div>
          </div>
        ))}
      </CardContent>
    </Card>
  )
}

// ---------------------------------------------------------------------------
// Error state
// ---------------------------------------------------------------------------

function IdentitySelectorError({
  className,
  error,
}: {
  className?: string
  error: Error
}) {
  return (
    <Card className={cn("w-full max-w-sm", className)}>
      <CardContent className="flex flex-col items-center gap-2 py-6">
        <AlertCircle className="size-5 text-destructive" />
        <p className="text-sm text-muted-foreground text-center">
          {error.message}
        </p>
      </CardContent>
    </Card>
  )
}

// ---------------------------------------------------------------------------
// Identity row
// ---------------------------------------------------------------------------

interface IdentityRowProps {
  identity: IdentityEntry
  isActive: boolean
  onSelect: (bapId: string) => void
}

function IdentityRow({ identity, isActive, onSelect }: IdentityRowProps) {
  const displayName = identity.name ?? identity.bapId.slice(0, 8)

  return (
    <button
      type="button"
      className={cn(
        "flex w-full items-center gap-3 rounded-md px-3 py-2.5 text-left transition-colors",
        isActive
          ? "bg-accent text-accent-foreground"
          : "hover:bg-muted/50",
      )}
      onClick={() => onSelect(identity.bapId)}
      aria-label={`Select identity ${displayName}`}
      aria-pressed={isActive}
    >
      <BitcoinAvatar
        address={identity.currentAddress}
        imageUrl={identity.imageUrl ?? undefined}
        size="md"
        className="shrink-0"
      />

      <div className="flex-1 min-w-0 flex flex-col gap-0.5">
        <p className="text-sm font-medium leading-tight truncate">
          {displayName}
        </p>
        <Badge
          variant="secondary"
          className="font-mono text-[10px] max-w-full break-all whitespace-normal leading-tight"
        >
          {identity.bapId}
        </Badge>
      </div>

      {isActive && (
        <Check
          className="size-4 shrink-0 text-primary"
          aria-label="Active identity"
        />
      )}
    </button>
  )
}

// ---------------------------------------------------------------------------
// Main UI component
// ---------------------------------------------------------------------------

export function IdentitySelectorUI({
  className,
  identities,
  activeBapId,
  isLoading,
  error,
  onSelect,
  onAddIdentity,
  showAddIdentity = true,
}: IdentitySelectorUIProps) {
  if (isLoading) {
    return <IdentitySelectorSkeleton className={className} />
  }

  if (error) {
    return <IdentitySelectorError className={className} error={error} />
  }

  if (identities.length === 0 && !showAddIdentity) {
    return (
      <Card className={cn("w-full max-w-sm", className)}>
        <CardContent className="flex flex-col items-center gap-2 py-6">
          <p className="text-sm text-muted-foreground">
            No identities available
          </p>
        </CardContent>
      </Card>
    )
  }

  return (
    <Card className={cn("w-full max-w-sm", className)}>
      <CardContent className="flex flex-col p-2">
        {identities.map((identity) => (
          <IdentityRow
            key={identity.bapId}
            identity={identity}
            isActive={identity.bapId === activeBapId}
            onSelect={onSelect}
          />
        ))}

        {showAddIdentity && (
          <>
            {identities.length > 0 && <Separator className="my-1" />}
            <Button
              variant="ghost"
              size="sm"
              className="w-full justify-start gap-2 text-muted-foreground hover:text-foreground"
              onClick={onAddIdentity}
            >
              <Plus data-icon="inline-start" />
              Add identity
            </Button>
          </>
        )}
      </CardContent>
    </Card>
  )
}

"use client"

import { useCallback, useEffect, useState } from "react"

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

/** A single BAP identity entry for the selector */
export interface IdentityEntry {
  /** BAP ID (~27 char base58 string) */
  bapId: string
  /** Display name from profile (schema.org name/alternateName) */
  name: string | null
  /** Current signing address (used for avatar seed) */
  currentAddress: string
  /** Avatar image URL (ord://, b://, https://) if available */
  imageUrl: string | null
}

/** BAP identity record returned from the 1sat-stack API */
interface BapIdentityRecord {
  idKey: string
  firstSeen: number
  rootAddress: string
  currentAddress: string
  addresses: Array<{ address: string; txId: string; block: number }>
  identity?: Record<string, unknown>
}

export interface UseIdentitySelectorOptions {
  /** Pre-loaded list of identities (skips API fetch if provided) */
  identities?: IdentityEntry[]
  /** BAP ID of the currently active identity */
  activeBapId?: string
  /** Called when the user selects a different identity */
  onSelect?: (bapId: string) => void
  /** Called when the user clicks "Add identity" */
  onAddIdentity?: () => void
  /** Base URL for the 1sat-stack API (default: https://api.1sat.app) */
  apiUrl?: string
  /** List of BAP IDs to fetch from the API (used when identities prop is not provided) */
  bapIds?: string[]
}

export interface UseIdentitySelectorReturn {
  /** List of available identities */
  identities: IdentityEntry[]
  /** Currently active BAP ID */
  activeBapId: string | null
  /** Whether identities are loading */
  isLoading: boolean
  /** Error if fetch failed */
  error: Error | null
  /** Select an identity by BAP ID */
  selectIdentity: (bapId: string) => void
  /** Handle "Add identity" action */
  addIdentity: () => void
}

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

const DEFAULT_API_URL = "https://api.1sat.app"

function extractName(identity: Record<string, unknown> | undefined): string | null {
  if (!identity) return null
  if (typeof identity.name === "string") return identity.name
  if (typeof identity.alternateName === "string") return identity.alternateName
  const parts = [
    typeof identity.givenName === "string" ? identity.givenName : null,
    typeof identity.familyName === "string" ? identity.familyName : null,
  ].filter(Boolean)
  return parts.length > 0 ? parts.join(" ") : null
}

function extractImageUrl(identity: Record<string, unknown> | undefined): string | null {
  if (!identity) return null
  if (typeof identity.image === "string") return identity.image
  return null
}

async function fetchIdentityEntry(
  bapId: string,
  apiUrl: string,
): Promise<IdentityEntry> {
  const res = await fetch(`${apiUrl}/1sat/bap/identity/get`, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({ idKey: bapId }),
  })
  if (!res.ok) {
    throw new Error(`Failed to fetch identity ${bapId}: ${res.status}`)
  }
  const data: BapIdentityRecord = await res.json()

  // Try to fetch profile for name/image
  let profileData: Record<string, unknown> | undefined
  try {
    const profileRes = await fetch(
      `${apiUrl}/1sat/bap/profile/${encodeURIComponent(bapId)}`,
    )
    if (profileRes.ok) {
      const raw: Record<string, unknown> = await profileRes.json()
      profileData = raw
    }
  } catch {
    // Profile may not exist; use identity data instead
  }

  const nameSource = profileData ?? data.identity
  return {
    bapId: data.idKey,
    name: extractName(nameSource),
    currentAddress: data.currentAddress,
    imageUrl: extractImageUrl(nameSource),
  }
}

// ---------------------------------------------------------------------------
// Hook
// ---------------------------------------------------------------------------

export function useIdentitySelector({
  identities: identitiesProp,
  activeBapId: activeBapIdProp,
  onSelect,
  onAddIdentity,
  apiUrl = DEFAULT_API_URL,
  bapIds,
}: UseIdentitySelectorOptions): UseIdentitySelectorReturn {
  const [identities, setIdentities] = useState<IdentityEntry[]>(
    identitiesProp ?? [],
  )
  const [activeBapId, setActiveBapId] = useState<string | null>(
    activeBapIdProp ?? null,
  )
  const [isLoading, setIsLoading] = useState(false)
  const [error, setError] = useState<Error | null>(null)

  // Sync externally provided identities
  useEffect(() => {
    if (identitiesProp) {
      setIdentities(identitiesProp)
    }
  }, [identitiesProp])

  // Sync externally provided active ID
  useEffect(() => {
    if (activeBapIdProp !== undefined) {
      setActiveBapId(activeBapIdProp)
    }
  }, [activeBapIdProp])

  // Fetch identities from API when bapIds are provided and no pre-loaded list
  useEffect(() => {
    if (identitiesProp || !bapIds || bapIds.length === 0) return

    let cancelled = false
    setIsLoading(true)
    setError(null)

    async function fetchAll() {
      try {
        const entries = await Promise.all(
          // biome-ignore lint: bapIds is checked above
          bapIds!.map((id) => fetchIdentityEntry(id, apiUrl)),
        )
        if (!cancelled) {
          setIdentities(entries)
          // Default active to first if none set
          if (!activeBapIdProp && entries.length > 0) {
            setActiveBapId(entries[0].bapId)
          }
        }
      } catch (err) {
        if (!cancelled) {
          setError(
            err instanceof Error
              ? err
              : new Error("Failed to load identities"),
          )
        }
      } finally {
        if (!cancelled) {
          setIsLoading(false)
        }
      }
    }

    void fetchAll()

    return () => {
      cancelled = true
    }
  }, [identitiesProp, bapIds, apiUrl, activeBapIdProp])

  const selectIdentity = useCallback(
    (bapId: string) => {
      setActiveBapId(bapId)
      onSelect?.(bapId)
    },
    [onSelect],
  )

  const addIdentity = useCallback(() => {
    onAddIdentity?.()
  }, [onAddIdentity])

  return {
    identities,
    activeBapId,
    isLoading,
    error,
    selectIdentity,
    addIdentity,
  }
}
